const SK='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';
const GT='pit-d626a99b-3a5e-4e51-aa5e-2371e4b2b5f6';
const GL='pit-f248c803-01d7-4970-a909-1f1badeebd45';
const NT='eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJzdWIiOiIxMjJmNmJmNi0zMDVmLTQwYmItODczYy0wMTA5YTMxMjJiMTAiLCJpc3MiOiJuOG4iLCJhdWQiOiJwdWJsaWMtYXBpIiwianRpIjoiMTczMTJmYTAtODA2MC00MTdlLWE4ZjEtZTMxYTZiOWE3M2FjIiwiaWF0IjoxNzczMTkzMzY4fQ.iP3Sd6P2D5TkrKDrjcfEpOteMr2ppXRk7AHy3evNyAA';

async function g(url, h) {
  try { const r = await fetch(url, {headers: h}); if (!r.ok) return null; return r.json(); }
  catch(e) { return null; }
}

const sH = {Authorization: 'Bearer ' + SK};
const gH = {Authorization: 'Bearer ' + GT, Version: '2021-07-28'};
const nH = {'X-N8N-API-KEY': NT};
const mS = new Date(); mS.setDate(1); mS.setHours(0,0,0,0);
const mSts = Math.floor(mS.getTime() / 1000);

const [sA, sPD, ch, gC, gO, wfD, exD] = await Promise.all([
  g('https://api.stripe.com/v1/subscriptions?status=active&limit=100&expand[]=data.customer', sH),
  g('https://api.stripe.com/v1/subscriptions?status=past_due&limit=100', sH),
  g('https://api.stripe.com/v1/charges?limit=15&created[gte]=' + mSts, sH),
  g('https://services.leadconnectorhq.com/contacts/?locationId=' + GL + '&limit=1', gH),
  g('https://services.leadconnectorhq.com/opportunities/search?location_id=' + GL + '&limit=100', gH),
  g('https://sunstatedigital.app.n8n.cloud/api/v1/workflows?limit=100', nH),
  g('https://sunstatedigital.app.n8n.cloud/api/v1/executions?limit=20&includeData=false', nH)
]);

const acts = (sA && sA.data) || [];
let mrr = 0;
const subs = acts.map(s => {
  let sm = 0;
  (s.items && s.items.data || []).forEach(i => {
    let a = i.price.unit_amount || 0;
    if (i.price && i.price.recurring && i.price.recurring.interval === 'year') a = Math.round(a/12);
    sm += a;
  });
  mrr += sm;
  return {id: s.id, customer_name: s.customer && (s.customer.name || s.customer.email) || 'Unknown', customer_email: s.customer && s.customer.email || '', mrr: sm, status: s.status, created: s.created, current_period_end: s.current_period_end};
});

const charges = (ch && ch.data) || [];
const mRev = charges.filter(c => c.status === 'succeeded').reduce((a,c) => a + c.amount, 0);
const wfs = (wfD && wfD.data) || [];
const exs = (exD && exD.data) || [];
const tc = (gC && (gC.meta && gC.meta.total || gC.total)) || 0;
const opps = (gO && (gO.opportunities || gO.data)) || [];

return [{json: {
  generated_at: new Date().toISOString(),
  stripe: {
    mrr, active_subscriptions: acts.length,
    past_due: (sPD && sPD.data && sPD.data.length) || 0,
    month_revenue: mRev,
    subscriptions: subs.sort((a,b) => b.mrr - a.mrr).slice(0,15),
    recent_charges: charges.slice(0,12).map(c => ({amount: c.amount, description: c.description || (c.billing_details && c.billing_details.name) || 'Charge', date: c.created, status: c.status}))
  },
  ghl: {
    total_contacts: tc,
    pipeline_value: opps.filter(o => o.status === 'open').reduce((a,o) => a + (o.monetaryValue||0), 0),
    opportunities: {open: opps.filter(o => o.status==='open').length, won: opps.filter(o => o.status==='won').length, lost: opps.filter(o => o.status==='lost').length, total: opps.length}
  },
  n8n: {
    total_workflows: wfs.length, active_workflows: wfs.filter(w => w.active).length,
    workflows: wfs.slice(0,25).map(w => ({id: w.id, name: w.name, active: w.active, updatedAt: w.updatedAt})),
    executions: exs.slice(0,20).map(e => ({id: e.id, workflowName: (e.workflowData && e.workflowData.name) || e.workflowId || 'Workflow', status: e.status || (e.finished ? 'success' : 'running'), startedAt: e.startedAt}))
  },
  openai: {note: 'Add api.usage.read key to enable token tracking'}
}}];
